-- ───── أذكار الصباح ─────
('أذكار الصباح', 'أَعُوذُ بِاللَّهِ مِنَ الشَّيْطَانِ الرَّجِيمِ. اللَّهُ لَا إِلَهَ إِلَّا هُوَ الْحَيُّ الْقَيُّومُ لَا تَأْخُذُهُ سِنَةٌ وَلَا نَوْمٌ لَهُ مَا فِي السَّمَاوَاتِ وَمَا فِي الْأَرْضِ مَنْ ذَا الَّذِي يَشْفَعُ عِنْدَهُ إِلَّا بِإِذْنِهِ يَعْلَمُ مَا بَيْنَ أَيْدِيهِمْ وَمَا خَلْفَهُمْ وَلَا يُحِيطُونَ بِشَيْءٍ مِنْ عِلْمِهِ إِلَّا بِمَا شَاءَ وَسِعَ كُرْسِيُّهُ السَّمَاوَاتِ وَالْأَرْضَ وَلَا يَئُودُهُ حِفْظُهُمَا وَهُوَ الْعَلِيُّ الْعَظِيمُ', 'آية الكرسي — رواه الحاكم والنسائي', 'من قالها حين يصبح أُجير من الجن حتى يمسي', 1, 1, true),
('أذكار الصباح', 'قُلْ هُوَ اللَّهُ أَحَدٌ ۝ اللَّهُ الصَّمَدُ ۝ لَمْ يَلِدْ وَلَمْ يُولَدْ ۝ وَلَمْ يَكُنْ لَهُ كُفُوًا أَحَدٌ', 'سورة الإخلاص — أبو داود والترمذي', 'من قالها مع المعوذتين ثلاثًا كفته من كل شيء', 3, 2, true),
('أذكار الصباح', 'أَصْبَحْنَا وَأَصْبَحَ الْمُلْكُ لِلَّهِ، وَالْحَمْدُ لِلَّهِ، لَا إِلَهَ إِلَّا اللَّهُ وَحْدَهُ لَا شَرِيكَ لَهُ، لَهُ الْمُلْكُ وَلَهُ الْحَمْدُ وَهُوَ عَلَى كُلِّ شَيْءٍ قَدِيرٌ، رَبِّ أَسْأَلُكَ خَيْرَ مَا فِي هَذَا الْيَوْمِ وَخَيْرَ مَا بَعْدَهُ، وَأَعُوذُ بِكَ مِنْ شَرِّ مَا فِي هَذَا الْيَوْمِ وَشَرِّ مَا بَعْدَهُ', 'رواه مسلم', NULL, 1, 3, true),
('أذكار الصباح', 'اللَّهُمَّ بِكَ أَصْبَحْنَا، وَبِكَ أَمْسَيْنَا، وَبِكَ نَحْيَا، وَبِكَ نَمُوتُ، وَإِلَيْكَ النُّشُورُ', 'رواه الترمذي', NULL, 1, 4, true),
('أذكار الصباح', 'اللَّهُمَّ أَنْتَ رَبِّي لَا إِلَهَ إِلَّا أَنْتَ، خَلَقْتَنِي وَأَنَا عَبْدُكَ، وَأَنَا عَلَى عَهْدِكَ وَوَعْدِكَ مَا اسْتَطَعْتُ، أَعُوذُ بِكَ مِنْ شَرِّ مَا صَنَعْتُ، أَبُوءُ لَكَ بِنِعْمَتِكَ عَلَيَّ، وَأَبُوءُ بِذَنْبِي فَاغْفِرْ لِي فَإِنَّهُ لَا يَغْفِرُ الذُّنُوبَ إِلَّا أَنْتَ', 'سيد الاستغفار — رواه البخاري', 'من قالها موقنًا بها فمات دخل الجنة', 1, 5, true),
('أذكار الصباح', 'اللَّهُمَّ إِنِّي أَصْبَحْتُ أُشْهِدُكَ، وَأُشْهِدُ حَمَلَةَ عَرْشِكَ، وَمَلَائِكَتَكَ، وَجَمِيعَ خَلْقِكَ، أَنَّكَ أَنْتَ اللَّهُ لَا إِلَهَ إِلَّا أَنْتَ وَحْدَكَ لَا شَرِيكَ لَكَ، وَأَنَّ مُحَمَّدًا عَبْدُكَ وَرَسُولُكَ', 'رواه أبو داود', NULL, 4, 6, true),
('أذكار الصباح', 'حَسْبِيَ اللَّهُ لَا إِلَهَ إِلَّا هُوَ عَلَيْهِ تَوَكَّلْتُ وَهُوَ رَبُّ الْعَرْشِ الْعَظِيمِ', 'رواه أبو داود', 'من قالها كفاه الله ما أهمه', 7, 7, true),
('أذكار الصباح', 'بِسْمِ اللَّهِ الَّذِي لَا يَضُرُّ مَعَ اسْمِهِ شَيْءٌ فِي الْأَرْضِ وَلَا فِي السَّمَاءِ وَهُوَ السَّمِيعُ الْعَلِيمُ', 'رواه أبو داود والترمذي', 'لم يضره شيء', 3, 8, true),
('أذكار الصباح', 'رَضِيتُ بِاللَّهِ رَبًّا، وَبِالْإِسْلَامِ دِينًا، وَبِمُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَبِيًّا', 'رواه أحمد والترمذي', 'كان حقًا على الله أن يرضيه يوم القيامة', 3, 9, true),
('أذكار الصباح', 'سُبْحَانَ اللَّهِ وَبِحَمْدِهِ', 'رواه مسلم', 'حُطَّت خطاياه وإن كانت مثل زبد البحر', 100, 10, true),

-- ───── أذكار المساء ─────
('أذكار المساء', 'أَمْسَيْنَا وَأَمْسَى الْمُلْكُ لِلَّهِ، وَالْحَمْدُ لِلَّهِ، لَا إِلَهَ إِلَّا اللَّهُ وَحْدَهُ لَا شَرِيكَ لَهُ، لَهُ الْمُلْكُ وَلَهُ الْحَمْدُ وَهُوَ عَلَى كُلِّ شَيْءٍ قَدِيرٌ، رَبِّ أَسْأَلُكَ خَيْرَ مَا فِي هَذِهِ اللَّيْلَةِ وَخَيْرَ مَا بَعْدَهَا، وَأَعُوذُ بِكَ مِنْ شَرِّ مَا فِي هَذِهِ اللَّيْلَةِ وَشَرِّ مَا بَعْدَهَا', 'رواه مسلم', NULL, 1, 1, true),
('أذكار المساء', 'اللَّهُمَّ بِكَ أَمْسَيْنَا، وَبِكَ أَصْبَحْنَا، وَبِكَ نَحْيَا، وَبِكَ نَمُوتُ، وَإِلَيْكَ الْمَصِيرُ', 'رواه الترمذي', NULL, 1, 2, true),
('أذكار المساء', 'أَعُوذُ بِكَلِمَاتِ اللَّهِ التَّامَّاتِ مِنْ شَرِّ مَا خَلَقَ', 'رواه مسلم', 'من قالها حين يمسي لم تضره حُمَةٌ تلك الليلة', 3, 3, true),
('أذكار المساء', 'اللَّهُمَّ عَافِنِي فِي بَدَنِي، اللَّهُمَّ عَافِنِي فِي سَمْعِي، اللَّهُمَّ عَافِنِي فِي بَصَرِي، لَا إِلَهَ إِلَّا أَنْتَ', 'رواه أبو داود', NULL, 3, 4, true),
('أذكار المساء', 'اللَّهُمَّ إِنِّي أَسْأَلُكَ الْعَفْوَ وَالْعَافِيَةَ فِي الدُّنْيَا وَالْآخِرَةِ، اللَّهُمَّ إِنِّي أَسْأَلُكَ الْعَفْوَ وَالْعَافِيَةَ فِي دِينِي وَدُنْيَايَ وَأَهْلِي وَمَالِي', 'رواه أبو داود وابن ماجه', NULL, 1, 5, true),

-- ───── أذكار بعد الصلاة ─────
('أذكار بعد الصلاة', 'أَسْتَغْفِرُ اللَّهَ', 'رواه مسلم', 'يُقال ثلاثًا بعد السلام', 3, 1, true),
('أذكار بعد الصلاة', 'اللَّهُمَّ أَنْتَ السَّلَامُ وَمِنْكَ السَّلَامُ، تَبَارَكْتَ يَا ذَا الْجَلَالِ وَالْإِكْرَامِ', 'رواه مسلم', NULL, 1, 2, true),
('أذكار بعد الصلاة', 'سُبْحَانَ اللَّهِ', 'رواه مسلم', 'ثلاثًا وثلاثين بعد كل صلاة', 33, 3, true),
('أذكار بعد الصلاة', 'الْحَمْدُ لِلَّهِ', 'رواه مسلم', 'ثلاثًا وثلاثين بعد كل صلاة', 33, 4, true),
('أذكار بعد الصلاة', 'اللَّهُ أَكْبَرُ', 'رواه مسلم', 'أربعًا وثلاثين، وتمام المئة: لا إله إلا الله وحده لا شريك له', 34, 5, true)

